#include<bits/stdc++.h>
using namespace std;
set<int>s;set<int>::iterator k,a;
int main(void){int n,x,ans=0;
    s.insert(500000000),s.insert(-500000000),cin>>n;
    for(int i=1;i<=n;i++){
        cin>>x;
        if(!(s.size()-2))ans+=x,s.insert(x);
        else{
            k=s.lower_bound(x);
            if(*k!=x)a=k,a--,ans+=min(abs(*a-x),abs(*k-x)),s.insert(x);
        }
    }cout<<ans;
    return false;
}
